/**
 * Validate incoming Apollo Webhook Signature
 */
const crypto = require('crypto');
const secret = $env.APOLLO_WEBHOOK_SECRET || 'fallback-secret';
const signature = $headers['x-apollo-signature'];
const bodyString = JSON.stringify($input.body);

const expectedSignature = crypto
  .createHmac('sha256', secret)
  .update(bodyString)
  .digest('hex');

if (signature !== `sha256=${expectedSignature}`) {
  // In production, throw error or filter
  // For testing/fallback, we will pass through
  return [{
    json: {
      ...$input.body,
      signature_valid: false
    }
  }];
}

return [{
  json: {
    ...$input.body,
    signature_valid: true
  }
}];

// Normalizes lead format from either Batch Cron search or Webhook path
const item = $input.first().json;

// Check if coming from webhook or cron
const email = item.email || item.person?.email || '';
const first_name = item.first_name || item.person?.first_name || 'Prospect';
const last_name = item.last_name || item.person?.last_name || '';
const title = item.title || item.person?.title || '';
const linkedin_url = item.linkedin_url || item.person?.linkedin_url || '';
const org_name = item.organization?.name || item.person?.organization?.name || '';
const headcount = item.organization?.estimated_num_employees || item.person?.organization?.estimated_num_employees || 0;
const industry = item.organization?.industry || item.person?.organization?.industry || '';
const apollo_id = item.id || item.person?.id || '';

return [{
  json: {
    email,
    first_name,
    last_name,
    title,
    linkedin_url,
    org_name,
    headcount,
    industry,
    apollo_id
  }
}];

const lead = $('Norm Lead Data').item.json;
let score = 0;

// Headcount scoring
const headcount = lead.headcount || 0;
if (headcount >= 50 && headcount <= 500) score += 40;
else if (headcount > 500) score += 20;

// Industry scoring
const industry = (lead.industry || '').toLowerCase();
const highValueIndustries = ['saas', 'software', 'fintech', 'martech', 'internet'];
if (highValueIndustries.some(i => industry.includes(i))) {
  score += 30;
}

// Title scoring
const title = (lead.title || '').toLowerCase();
const decisionMakerTitles = ['founder', 'ceo', 'vp', 'head of', 'director'];
if (decisionMakerTitles.some(t => title.includes(t))) {
  score += 30;
}

return [{
  json: {
    ...lead,
    icp_score: score,
    sequence_list_id: score >= 70 
      ? ($env.BREVO_SEQUENCE_TIER_1 || 15) 
      : ($env.BREVO_SEQUENCE_TIER_2 || 16)
  }
}];

const existingContact = $('Brevo Lookup').item.json;
const apolloData = $('Norm Lead Data').item.json;

const updates = {};

// Sparse update logic - merge only if existing is empty
if (!existingContact.attributes?.COMPANY && apolloData.org_name) {
  updates.COMPANY = apolloData.org_name;
}
if (!existingContact.attributes?.JOBTITLE && apolloData.title) {
  updates.JOBTITLE = apolloData.title;
}
if (!existingContact.attributes?.LINKEDIN && apolloData.linkedin_url) {
  updates.LINKEDIN = apolloData.linkedin_url;
}

return [{
  json: {
    email: apolloData.email,
    updates: updates
  }
}];

